import java.sql.*; public class DeleteStudents { public static void main(String[] args) throws Exception { Class.forName("org.sqlite.JDBC"); Connection c = DriverManager.getConnection("jdbc:sqlite:alip_data.db"); Statement s = c.createStatement(); int count1 = s.executeUpdate("DELETE FROM student_scores"); int count2 = s.executeUpdate("DELETE FROM subjects"); int count3 = s.executeUpdate("DELETE FROM goals"); int count4 = s.executeUpdate("DELETE FROM interventions"); int count5 = s.executeUpdate("DELETE FROM reevaluations"); int count6 = s.executeUpdate("DELETE FROM students"); System.out.println("Deleted " + count6 + " students and related data."); s.close(); c.close(); } }
